sp_angular_provider.script:
function scmTableAppliedFiltersService($sce) {
    "use strict";

    function nextRequestId(currentRequestId) {
        return (currentRequestId || 0) + 1;
    }

    function emptyHtml() {
        return $sce.trustAsHtml("<span></span>");
    }

    function sanitizeTrustedHtml(html) {
        if (!html) {
            return emptyHtml();
        }

        if (typeof DOMParser === "undefined") {
            return emptyHtml();
        }

        var parser = new DOMParser();
        var parsed = parser.parseFromString(String(html), "text/html");

        parsed
            .querySelectorAll("script, iframe, object, embed")
            .forEach(function (node) {
                node.remove();
            });

        parsed.querySelectorAll("*").forEach(function (node) {
            Array.from(node.attributes).forEach(function (attribute) {
                var name = attribute.name.toLowerCase();
                var value = String(attribute.value || "").toLowerCase();

                if (name.indexOf("on") === 0) {
                    node.removeAttribute(attribute.name);
                }

                if (
                    (name === "href" || name === "src") &&
                    value.indexOf("javascript:") === 0
                ) {
                    node.removeAttribute(attribute.name);
                }
            });
        });

        return $sce.trustAsHtml(parsed.body.innerHTML || "<span></span>");
    }

    function getAppliedFiltersInfoMessage(options) {
        options = options || {};

        return options.server.get({
            action: "getAppliedFiltersInfoMessage",
            transactionId: options.transactionId,
            tableProviderScriptInclude: options.tableProviderScriptInclude,
            appliedFilters: options.appliedFilters || [],
        });
    }

    function refreshAppliedFiltersHtml(options) {
        options = options || {};

        var currentRequestId = options.currentRequestId || 0;
        var requestId = nextRequestId(currentRequestId);
        var setRequestId = options.setRequestId;

        if (typeof setRequestId === "function") {
            setRequestId(requestId);
        }

        if (typeof options.setHtml === "function") {
            options.setHtml(emptyHtml());
        }

        return getAppliedFiltersInfoMessage(options)
            .then(function (response) {
                var latestRequestId =
                    typeof options.getCurrentRequestId === "function"
                        ? options.getCurrentRequestId()
                        : requestId;

                if (requestId !== latestRequestId) {
                    return { requestId: requestId, html: emptyHtml() };
                }

                var htmlContent =
                    (response &&
                        response.data &&
                        response.data.appliedFiltersHtml) ||
                    "";
                var sanitized = sanitizeTrustedHtml(htmlContent);

                if (typeof options.setHtml === "function") {
                    options.setHtml(sanitized);
                }

                return { requestId: requestId, html: sanitized };
            })
            .catch(function () {
                var latestRequestId =
                    typeof options.getCurrentRequestId === "function"
                        ? options.getCurrentRequestId()
                        : requestId;

                if (requestId !== latestRequestId) {
                    return { requestId: requestId, html: emptyHtml() };
                }

                var html = emptyHtml();
                if (typeof options.setHtml === "function") {
                    options.setHtml(html);
                }

                return { requestId: requestId, html: html };
            });
    }

    return {
        nextRequestId: nextRequestId,
        emptyHtml: emptyHtml,
        sanitizeTrustedHtml: sanitizeTrustedHtml,
        getAppliedFiltersInfoMessage: getAppliedFiltersInfoMessage,
        refreshAppliedFiltersHtml: refreshAppliedFiltersHtml,
    };
}
